INSERT INTO carsMaps_company (id, name, logo_url, description) VALUES (1, 'Mahindra', 'https://www.google.com/url?sa=i&url=https%3A%2F%2Fwww.shutterstock.com%2Fsearch%2Fmahindra-logo&psig=AOvVaw3JICYV0XIfqLWPE8la_Uut&ust=1721190474293000&source=images&cd=vfe&opi=89978449&ved=0CBQQjRxqFw', 'This flagship company of Mahindra group was built in 1945 to manufacture vehicles for general use. Today, it has become the 10th biggest car manufacturing company in India in the private sector. The company manufactures tractors and general & commercial utility vehicles. Some of the popular car brands offered by the company are:INSERT INTO carsMaps_company (id, name, logo_url, description) VALUES (2, 'BMW', 'https://www.google.com/url?sa=i&url=https%3A%2F%2Fwww.shutterstock.com%2Fsearch%2Fmahindra-logo&psig=AOvVaw3JICYV0XIfqLWPE8la_Uut&ust=1721190474293000&source=images&cd=vfe&opi=89978449&ved=0CBQQjRxqFw', 'BMW car price starts at Rs 43.90 Lakh for the cheapest model which is 2 Series Gran Coupe and the price of most expensive model, which is XM starts at Rs 2.60 Crore. BMW offers 21 car models in India, including 9 cars in SUV category, 7 cars in Sedan category, 1 car in Convertible category, 4 cars in Coupe category. BMW has 2 upcoming cars in India, New 5 Series and New X3.INSERT INTO carsMaps_news (id, title, summary, image_url, url) VALUES (1, 'BMW', 'BMW car price starts at Rs 43.90 Lakh for the cheapest model which is 2 Series Gran Coupe and the price of most expensive model, which is XM starts at Rs 2.60 Crore. BMW offers 21 car models in India, including 9 cars in SUV category, 7 cars in Sedan category, 1 car in Convertible category, 4 cars in Coupe category. BMW has 2 upcoming cars in India, New 5 Series and New X3.INSERT INTO carsMaps_profitdata (id, year, profit, company_id) VALUES (1, 2024, 12345, 1);
