INSERT INTO truck_bustype (id, name, description) VALUES (2, 'Tour buses', 'Make your car ownership journey a smooth ride with Mahindra Finance. We offer Car Loans that cater to your needs, with up to 100% financing on ex-showroom value from top brands like Mahindra, Hyundai, TATA Motors, Maruti Suzuki, Renault, and others. Our flexible repayment tenure and affordable EMIs make owning a car a hassle-free experience. Our expert team is always ready to assist you with the loan application process and ensure a seamless experience. Get your dream car today with Mahindra Finance!');
INSERT INTO truck_overview (id, title, content, image) VALUES (1, 'Buses in India', 'The market for buses in India has really picked up. The auto expo 2010 showcased a few new automobile giants trying to make their way into the Indian heavy vehicle industry. Auto giants such as Tata Motors and Ashok Leyland who almost enjoyed a sort of shared monopoly now have reason to put their thinking caps on. Automobile giants such as Mercedes Benz have set their foot into the Indian bus market and are all set to roll with their latest 3-axle intercity luxury bus priced at Rs. 85 lakh to Rs. 90 lakh. The demand for buses in India, be it public buses or luxury buses just seems to be on a continuous rise. The year 2009 saw a host of new public transport buses with latest technologies gliding the Indian roads but there is still much more to come. Domestic giants Ashok Leyland alone sold 63,926 units in the year 2009-10, as against 54,431 units in the previous year, posting a growth of 17.4 per cent.INSERT INTO truck_overview (id, title, content, image) VALUES (2, 'buses', 'Make your car ownership journey a smooth ride with Mahindra Finance. We offer Car Loans that cater to your needs, with up to 100% financing on ex-showroom value from top brands like Mahindra, Hyundai, TATA Motors, Maruti Suzuki, Renault, and others. Our flexible repayment tenure and affordable EMIs make owning a car a hassle-free experience. Our expert team is always ready to assist you with the loan application process and ensure a seamless experience. Get your dream car today with Mahindra Finance!', '');
