INSERT INTO usefulInfo_article (id, title, content, slug, created_at, updated_at) VALUES (1, 'honda bike', 'Make your car ownership journey a smooth ride with Mahindra Finance. We offer Car Loans that cater to your needs, with up to 100% financing on ex-showroom value from top brands like Mahindra, Hyundai, TATA Motors, Maruti Suzuki, Renault, and others. Our flexible repayment tenure and affordable EMIs make owning a car a hassle-free experience. Our expert team is always ready to assist you with the loan application process and ensure a seamless experience. Get your dream car today with Mahindra Finance!', 'good', '2024-07-24 09:32:53.964008', '2024-07-24 09:32:53.964063');
INSERT INTO usefulInfo_automobileinfo (id, title, content, last_updated, slug) VALUES (1, 'Understanding ABS Brakes', 'Anti-lock Braking System (ABS) prevents wheels from locking during hard braking. It allows steering control while braking maximally. ABS works by rapidly pumping brakes when it detects wheel lock.
INSERT INTO usefulInfo_automobileinfo (id, title, content, last_updated, slug) VALUES (2, 'Airbag Safety Systems', 'Airbags supplement seatbelts in frontal collisions. They deploy in milliseconds when sensors detect severe impact. Modern vehicles may have multiple airbags: front, side, curtain, and knee airbags.
INSERT INTO usefulInfo_automobileinfo (id, title, content, last_updated, slug) VALUES (3, 'Transmission Types Explained', 'Manual transmissions offer driver control and typically better fuel efficiency. They require clutch operation and gear selection. Learning curve exists but many drivers prefer the engagement.
INSERT INTO usefulInfo_automobiletip (id, title, content, order) VALUES (1, 'Emergency Kit Essentials', 'Every vehicle should have an emergency kit: spare tire, jack, jumper cables, basic tools, flashlight, first-aid supplies, water, and emergency contact numbers. Check and replenish every six months.', 1);
INSERT INTO usefulInfo_automobiletip (id, title, content, order) VALUES (2, 'Fuel Efficiency Hacks', 'Maintain steady speeds, avoid excessive idling, keep windows closed at high speeds, remove roof racks when not needed, and use air conditioning judiciously to maximize fuel efficiency.', 2);
INSERT INTO usefulInfo_automobiletip (id, title, content, order) VALUES (3, 'Monsoon Driving Safety', 'Check tire tread depth, replace worn wipers, ensure working defrosters, drive slower in wet conditions, maintain greater following distance, and avoid flooded roads during monsoon season.', 3);
INSERT INTO usefulInfo_automobiletip (id, title, content, order) VALUES (4, 'Battery Maintenance', 'Clean battery terminals regularly, check electrolyte levels, ensure tight connections, test battery voltage monthly, and replace batteries every 3-4 years for reliable performance.', 4);
INSERT INTO usefulInfo_automobiletip (id, title, content, order) VALUES (5, 'Summer Vehicle Care', 'Check coolant levels, test AC performance, inspect hoses for cracks, monitor tire pressure (increases with heat), and park in shade when possible during hot summer months.', 5);
INSERT INTO usefulInfo_infoarticle (id, title, slug, content, last_updated) VALUES (1, 'Monthly Vehicle Maintenance', 'monthly-vehicle-maintenance', 'Monthly checks keep your vehicle running smoothly. Check tire pressure when cold - including the spare. Inspect tread wear using the coin test. Check all fluid levels: engine oil, coolant, brake fluid, and windshield washer.
INSERT INTO usefulInfo_infoarticle (id, title, slug, content, last_updated) VALUES (2, 'Pre-Trip Vehicle Inspection', 'pre-trip-vehicle-inspection', 'Before long journeys, perform thorough checks. Verify tire condition and pressure. Check oil level and top up if needed. Ensure coolant is at proper level. Test brakes for proper operation.
INSERT INTO usefulInfo_infoarticle (id, title, slug, content, last_updated) VALUES (3, 'Winter Vehicle Preparation', 'winter-vehicle-preparation', 'Winter requires special vehicle preparation. Install winter tires if temperatures regularly drop below 7°C. Check antifreeze concentration and protection level. Test battery health - cold weather reduces battery efficiency.
INSERT INTO usefulInfo_motorpolicy (id, title, content, last_updated) VALUES (1, 'Comprehensive Motor Insurance Policy', 'This policy covers damages to your vehicle as well as third-party liability. It includes protection against theft, natural disasters, and accidents.",', '2025-02-20 11:56:59.330127');
INSERT INTO usefulInfo_motorpolicy (id, title, content, last_updated) VALUES (2, 'Third-Party Liability Policy', 'Covers damages and legal liabilities to a third party in case of an accident caused by the insured vehicle.', '2025-02-20 11:58:27.572448');
INSERT INTO usefulInfo_motorpolicy (id, title, content, last_updated) VALUES (3, 'Personal Accident Cover', 'Provides financial assistance in case of injury, disability, or death of the owner-driver due to a vehicle accident.', '2025-02-20 11:59:06.012799');
INSERT INTO usefulInfo_motorpolicy (id, title, content, last_updated) VALUES (4, 'Zero Depreciation Policy', 'Ensures full claim amount without considering vehicle depreciation on replaced parts during repairs.', '2025-02-20 12:01:24.800205');
INSERT INTO usefulInfo_motorpolicy (id, title, content, last_updated) VALUES (5, 'Pay-as-You-Drive Policy', 'Offers customized premiums based on actual vehicle usage. Ideal for people who drive less.', '2025-02-20 12:03:58.654255');
INSERT INTO usefulInfo_useful (id, title, slug, content, last_updated) VALUES (1, 'How to Improve Car Mileage', 'how-to-improve-car-mileage', 'Improving your car''s fuel efficiency is easier than you might think. Start by maintaining proper tire pressure - underinflated tires can reduce fuel economy by up to 3%. Regular engine maintenance is crucial; clean air filters and proper oil changes help your engine run more efficiently. 
INSERT INTO usefulInfo_useful (id, title, slug, content, last_updated) VALUES (2, 'Basic Bike Maintenance Checklist', 'basic-bike-maintenance-checklist', 'Regular motorcycle maintenance ensures safety and longevity. Check tire pressure before every ride - proper inflation improves handling and fuel efficiency. Inspect tread depth and look for signs of wear or damage.
INSERT INTO usefulInfo_useful (id, title, slug, content, last_updated) VALUES (3, 'Petrol vs Diesel: Making the Right Choice', 'petrol-vs-diesel-making-the-right-choice', 'Choosing between petrol and diesel engines depends on your driving needs. Diesel engines typically offer better fuel economy and torque, making them ideal for long-distance highway driving and heavy loads.
INSERT INTO usefulInfo_useful (id, title, slug, content, last_updated) VALUES (4, 'EV Charging Tips for Indian Drivers', 'ev-charging-tips-for-indian-drivers', 'Electric vehicle charging in India requires planning. Home charging is most convenient - install a dedicated 15-amp socket with proper earthing. A full charge typically takes 6-8 hours using standard home charging.
INSERT INTO usefulInfo_useful (id, title, slug, content, last_updated) VALUES (5, 'When to Service Your Vehicle', 'when-to-service-your-vehicle', 'Regular vehicle servicing prevents breakdowns and extends lifespan. Follow your manufacturer''s recommended schedule, typically every 5,000-10,000 km or 6-12 months, whichever comes first.
INSERT INTO usefulInfo_useful (id, title, slug, content, last_updated) VALUES (6, 'Understanding Vehicle Insurance Basics', 'understanding-vehicle-insurance-basics', 'Vehicle insurance is mandatory in India. Third-party insurance covers damage to other vehicles and property, but not your own vehicle. Comprehensive coverage includes third-party plus damage to your own vehicle.
