INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (1, 'The Early Beginnings of Automobile History', 'Horses had dreams of them since time immemorial, but it was only in the 18th century that the first horseless carriage actually hit the roads. The History of the automobile actually began about 4,000 years ago when the first wheel was used for transportation in India', 'early-beginnings-automobile-histo', '2024-07-29 04:42:59.646199', '2024-07-29');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (2, 'Wind-Driven Cars: Early Concept', 'Several Italians recorded designs for wind-driven cars. The first was Guido da Vigevano in 1335. It was a windmill-type drive to gears and thus to wheels. Vaturio designed a similar car that was also never built.', 'wind-driven-cars-early-concepts', '2024-07-29 05:04:13.453296', '2024-07-29');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (3, 'A Carriage That Moves On Its Own', 'The dream a carriage that moved on its own was realized only in the 18th century when the first car rolled on the streets. Steam, petroleum gas, electricity or petrol (sold at the chemist''s in the beginning) started being used for driving these funny car s that looked more or less like horseless carriages.', 'a-carriage-that-moves-on-its-own', '2024-07-29 05:54:51.380633', '2024-07-29');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (4, 'Cugnot''s Steam-Powered Vehicle', 'Nicolas-Joseph Cugnot invented the first self-propelled vehicle in 1769. It used steam power for locomotion and found military application in the French army. However, Cugnot''s automobile was never commercially sold.', 'cugnots-steam-powered-vehicle', '2024-08-08 10:00:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (5, 'Era of Steam-Powered Vehicles', 'In the beginning, the automobile industry was dominated by steam-powered vehicles. These vehicles were expensive, difficult to maintain, and prone to boiler explosions, which deterred potential purchasers.', 'era-of-steam-powered-vehicles', '2024-08-08 10:05:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (6, 'Karl Benz and the First Gasoline-Powered Vehicle', 'The commercial history of automobiles started with the invention of gasoline-powered internal combustion engines. German inventor Karl Benz constructed his first gasoline-powered vehicle in 1885 at Mannheim, Germany.', 'karl-benz-first-gasoline-vehicle', '2024-08-08 10:10:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (7, 'Commercial Production of Benz Cars', 'Commercial production of Benz cars started in 1888, marking a significant milestone in automotive history.', 'commercial-production-benz-cars', '2024-08-08 10:15:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (8, 'Panhard et Levassor: First Exclusive Car Manufacturer', 'Panhard et Levassor of France was the first company to exclusively build and sell motor cars, starting in 1889.', 'panhard-et-levassor-first-car-manufacturer', '2024-08-08 10:20:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (9, 'Rise of Automobile Manufacturing Companies', 'The early 1900s saw many automobile manufacturing companies coming into existence in various European countries and the United States.', 'rise-of-automobile-manufacturing-companies', '2024-08-08 10:25:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (10, 'The Curved-Dash Oldsmobile', 'The first mass-produced automobile in the United States was the curved-dash Oldsmobile. It was a three-horsepower machine and sold 5,000 units by 1904.', 'curved-dash-oldsmobile', '2024-08-08 10:30:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (11, 'Henry Ford and the Model T', 'The economics of the US car market was disrupted by the arrival of Henry Ford and his Model T car. The Model T was the world''s first mass-produced vehicle, with a million units sold by 1920, just 10 years after its introduction.', 'henry-ford-model-t', '2024-08-08 10:35:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (12, 'The Assembly Line Revolution', 'In 1913, Henry Ford introduced the moving assembly line, revolutionizing automobile production and significantly reducing manufacturing time and costs.', 'assembly-line-revolution', '2024-08-08 10:40:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (13, 'The Rise of General Motors', 'General Motors was founded in 1908 by William C. Durant. It grew to become one of the largest automobile manufacturers in the world.', 'rise-of-general-motors', '2024-08-08 10:45:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (14, 'The First Electric Starter', 'Charles Kettering invented the electric starter in 1911, eliminating the need for hand-cranking and making cars much easier to start.', 'first-electric-starter', '2024-08-08 10:50:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (15, 'The Advent of Four-Wheel Brakes', 'In the 1920s, four-wheel brake systems were introduced, significantly improving vehicle safety.', 'advent-four-wheel-brakes', '2024-08-08 10:55:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (16, 'The First Automatic Transmission', 'General Motors introduced the first automatic transmission, called the Hydra-Matic, in 1940.', 'first-automatic-transmission', '2024-08-08 11:00:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (17, 'The Volkswagen Beetle', 'The Volkswagen Beetle, designed in the 1930s, became one of the best-selling cars of all time, with production continuing until 2003.', 'volkswagen-beetle', '2024-08-08 11:05:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (18, 'The Rise of Japanese Automakers', 'In the 1960s and 1970s, Japanese automakers like Toyota and Honda began to gain significant market share in the global automotive industry.', 'rise-of-japanese-automakers', '2024-08-08 11:10:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (19, 'The Oil Crisis and Fuel Efficiency', 'The 1973 oil crisis led to a greater emphasis on fuel efficiency in automobile design and production.', 'oil-crisis-fuel-efficiency', '2024-08-08 11:15:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (20, 'The Introduction of Airbags', 'Airbags were first introduced in the 1970s and became standard safety features in most vehicles by the 1990s.', 'introduction-of-airbags', '2024-08-08 11:20:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (21, 'The First Hybrid Car', 'The Toyota Prius, launched in 1997, was the first mass-produced hybrid electric vehicle.', 'first-hybrid-car', '2024-08-08 11:25:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (22, 'The Rise of Tesla and Electric Vehicles', 'Tesla Motors, founded in 2003, played a significant role in popularizing electric vehicles in the 21st century.', 'tesla-and-electric-vehicles', '2024-08-08 11:30:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (23, 'The Development of Self-Driving Cars', 'In the 2010s, major automakers and tech companies began developing and testing self-driving car technologies.', 'development-self-driving-cars', '2024-08-08 11:35:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (24, 'The Diesel Engine', 'Rudolf Diesel invented the diesel engine in 1893, which later became widely used in trucks and some passenger vehicles.', 'diesel-engine', '2024-08-08 11:40:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (25, 'The First Car Radio', 'The first car radio was introduced in the 1930s, changing the driving experience forever.', 'first-car-radio', '2024-08-08 11:45:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (26, 'The Introduction of Power Steering', 'Power steering was first introduced in the 1951 Chrysler Imperial, making driving easier and more comfortable.', 'introduction-power-steering', '2024-08-08 11:50:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (27, 'The Rotary Engine', 'Mazda popularized the rotary engine in cars with its RX series, starting in the 1960s.', 'rotary-engine', '2024-08-08 11:55:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (28, 'The Rise of SUVs', 'Sport Utility Vehicles (SUVs) gained immense popularity in the 1990s and 2000s, changing the landscape of the automotive market.', 'rise-of-suvs', '2024-08-08 12:00:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (29, 'The Development of Crash Tests', 'Crash testing became standardized in the 1970s, leading to significant improvements in vehicle safety.', 'development-crash-tests', '2024-08-08 12:05:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (30, 'The First Turbocharged Production Car', 'The Oldsmobile Jetfire and the Chevrolet Corvair Monza were the first turbocharged production cars, both introduced in 1962.', 'first-turbocharged-production-car', '2024-08-08 12:10:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (31, 'The Introduction of Anti-lock Braking Systems', 'Anti-lock Braking Systems (ABS) were first introduced in production cars in the 1970s, significantly improving vehicle safety.', 'introduction-abs', '2024-08-08 12:15:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (32, 'The First GPS Navigation System in Cars', 'The first GPS navigation system for automobiles was introduced in the 1990s, revolutionizing how people navigate while driving.', 'first-gps-navigation-system', '2024-08-08 12:20:00', '2024-08-08');
INSERT INTO automobile_company_historyarticle (id, title, content, slug, published_date, last_updated) VALUES (33, 'The Development of Catalytic Converters', 'Catalytic converters were introduced in the 1970s to reduce harmful emissions from automobiles.', 'development-catalytic-converters', '2024-08-08 12:25:00', '2024-08-08');
INSERT INTO automobile_company_additive (id, name, purpose) VALUES (1, 'Diesel Engine Additive for Automobiles', 'Plain mineral oils cannot provide all the necessary functional properties that an engine requires. These plain mineral oils need fortification with chemicals/additives which when used in small quantities, import or enhance the desirable functional properties. Some of the types and reasons for their use are as follows:INSERT INTO automobile_company_additive (id, name, purpose) VALUES (2, 'Dispersants', 'Keeps sludge, carbon, and other deposit precursors suspended in oil. Keeps engine parts clean from deposits and prevents buildup.');
INSERT INTO automobile_company_additive (id, name, purpose) VALUES (3, 'Rust/Corrosion Inhibitors', 'Prevents or controls oxidation, varnish formation, and corrosion.');
INSERT INTO automobile_company_additive (id, name, purpose) VALUES (4, 'Extreme Pressure (EP) Additives', 'Forms a protective film on engine parts to reduce wear and tear.');
INSERT INTO automobile_company_lubricant (id, name, description, usage) VALUES (1, 'Synthetic Oil', 'Synthetic oil offers improved engine performance, reduced oil consumption, and longer drain intervals compared to mineral oils.', 'Used in high-performance cars and for better engine cleanliness and faster starting.');
