INSERT INTO carshanders_news (id, title, summary, image_url, url, image) VALUES (1, 'BMW Unveils the All-New BMW X7: A Luxurious Adventure Awaits', 'BMW has just launched its latest luxury SUV, the BMW X7. Combining cutting-edge technology with unmatched comfort, the new X7 promises a refined driving experience with advanced features, spacious interiors, and a powerful engine lineup. Ideal for those seeking both performance and elegance in their next adventure.', 'https://example.com/bmw-x7-launch-image.jpg', 'https://example.com/bmw-x7-launch-news', 'images/iron_883.jpg');
INSERT INTO carshanders_news (id, title, summary, image_url, url, image) VALUES (2, 'Tesla Reveals New Model S Plaid: The Fastest Production Car Ever', 'Tesla has introduced the new Model S Plaid, boasting unprecedented acceleration and top speeds. With a refined design and advanced autopilot features, the Model S Plaid sets new standards for electric performance and luxury.', 'https://example.com/tesla-model-s-plaid.jpg', 'https://example.com/tesla-model-s-plaid-news', 'images/iron_883.jpg');
