INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (1, 'Starter', 'A device used to rotate an internal-combustion engine so as to initiate the engine''s operation under its own power.', 120, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (2, 'Armature', 'The rotating coil or coils of a dynamo or electric motor.', 75, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (3, 'Commutator', 'A rotary switch in certain types of electric motors and electrical generators that periodically reverses the current direction between the rotor and the external circuit.', 50, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (4, 'Field Coil', 'An electromagnet used to generate a magnetic field in an electro-magnetic machine, typically a rotating electrical machine such as a motor or generator.', 80, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (5, 'Starter Bendix Drive', 'A starter drive which incorporates a one-way clutch and a helical drive spring to engage the engine''s flywheel during starting.', 95, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (6, 'Alternator', 'A generator that produces alternating current.', 150, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (7, 'Rotor', 'The rotating part of an electrical or mechanical device.', 85, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (8, 'Stator', 'The stationary part of a rotary system, found in electric generators, electric motors, sirens, mud motors or biological rotors.', 90, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (9, 'Housing', 'A durable protective casing or enclosure for an electrical device or system.', 40, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (10, 'Flash Relay', 'A relay that interrupts the flow of electrical current at regular intervals to produce a flashing signal.', 20, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (11, 'Carbon Brush', 'An electrical contact which conducts current between stationary wires and moving parts, most commonly in a rotating shaft.', 10, '', 1);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (12, 'Hub Bolt', 'A bolt used to secure the wheel hub to the vehicle.', 5, '', 2);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (13, 'T-Bolt', 'A bolt with a T-shaped head that fits into a slot or channel.', 3, '', 2);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (14, 'Washer', 'A flat disk typically used to distribute the load of a threaded fastener, such as a bolt or nut.', 0.5, '', 2);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (15, 'Nut', 'A fastener with a threaded hole, typically used in conjunction with a mating bolt to fasten multiple parts together.', 0.75, '', 2);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (16, 'U-Bolt', 'A bolt in the shape of the letter U, typically used to support pipework or as a clamp.', 4, '', 2);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (17, 'Gear', 'A rotating machine part having cut teeth or cogs which mesh with another toothed part to transmit torque.', 30, '', 3);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (18, 'Tie-Rod End', 'A part of the steering mechanism in a vehicle that connects the steering rack to the steering knuckle.', 25, '', 3);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (19, 'Ball Joint', 'A spherical bearing that connects the control arms to the steering knuckles.', 20, '', 3);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (20, 'U-J Cross', 'A universal joint cross, a coupling in a rigid rod that allows the rod to ''bend'' in any direction.', 15, '', 3);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (21, 'Brake Hose', 'A flexible hose that carries brake fluid from the brake line to the brake caliper.', 10, '', 4);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (22, 'Fuel Line', 'A hose or pipe used to transfer fuel from the fuel tank to the engine.', 12, '', 4);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (23, 'Engine Mounting', 'A support that secures the engine to the chassis and absorbs vibrations.', 30, '', 4);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (24, 'Support', 'A bracket or fixture used to support or secure an automotive component.', 8, '', 4);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (25, 'Brake Pipe', 'A rigid pipe that carries brake fluid from the master cylinder to the brake calipers or wheel cylinders.', 15, '', 4);
INSERT INTO carshanders_spare (id, name, description, price, image, category_id) VALUES (26, 'Fuel Injection Pipe', 'A pipe used to deliver fuel under high pressure from the fuel pump to the injectors.', 20, '', 4);
