INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (1, 'The Benz Vehicle', 1886, 'It is accorded the distinction of being the first gasoline-powered vehicle. This three-wheeler was the first car equipped with a differential gear and had a horizontal, four-cycle single-cylinder engine. The engine was mounted horizontally behind the seat, over the rear axle, in a frame-developed form prevailing tricycles. Its 0.9 horsepower was transmitted to the rear wheels via belt and chain, enabling a top speed of about 15 km/h. A lever connected to a rack-and-pinion controlled the lone front wheel, which steered the car.', 3);
INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (2, 'Baker Electric', 1899, 'For a long period after gasoline-powered cars gained popularity, battery-powered cars continued to be made in the United States. The Baker was produced from 1899 to 1915. The unusual suspension of this car consisted of attaching the wheel shafts directly to the frame, on top of which was mounted a body on springs. The body carried the motor, which drove the rear wheels by a chain. A lever next to the driving seat controlled its speed. The Baker Electric was reputedly easy to drive, and could cruise a distance of 80 km when fully charged, reaching a top speed of 40 km/h.', 3);
INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (3, 'Stanley Streamer/Stanley Streamer', 1927, 'The steam car, Stanley Steamer continued production until 1927. It was quiet, had little vibration, produced sufficient torque, and was easy to handle. Under the bonnet of this car was a boiler, which provided the pressure to drive a two-cylinder engine located beneath the floor. Because of its abundant torque, the Stanley Steamer did not have a transmission-just one gear engaged the center of its crankshaft, and directly turned the rear wheels. Manipulating the Steamer''s valves, which controlled the flow of fuel, water, and steam, must have required quite a bit of practice and knowledge. Although it could achieve a higher top speed than its gasoline-driven rivals, it was hard to start, especially in the cold weather.', 3);
INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (4, 'Panhard et Levassor (France)', 1891, 'Two French toolmakers Rene Panhard and Emile Levassor were the first to propose and commercialize a car having a layout and structure similar to today''s cars. The Panhard et Levassor was the origin of the classic front engine, rear-wheel drive layout, the paradigm that transformed the horseless carriage into the car as we know it today. It positioned its transmission in line with the engine and clutch, and had a steering wheel instead of a tiller, and an in-line four-cylinder engine. The front engine gave the car a better balance and made it easier to steer.', 3);
INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (5, 'Mercedes', 1901, 'The new Daimler model combined into one machine for the first time all the vital features of the modern car : a powerful four-cylinder engine, a pressed steel chassis, a honeycomb radiator, and a recognizably modern gear stick moving in a gate. The model was named Mercedes, after the daughter of an Austrian, Emily Jellinek, the Daimler representative in France.', 3);
INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (6, 'Tin Lizzie or T Model', 1907, 'Henry Ford''s model T, popularly called the Tin Lizzy, was the first everyman''s car .It not only brought motoring to the masses but also was the first mass-produced car . As result, automobile ownership surged and car s became affordable for the ordinary wage earner as well. The Model T introduced various features to facilitate driving, and the transmission was integrated with the engine. Its planetary gears-two forward and one back-could be shifted without the use of a clutch.INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (7, 'The Morris and the Austin Seven', 1922, 'The bull-nosed Morris launched the family car in Britain. In the 1920s, this popular line could be bought for as little as $775, at $115 down and about $9 per week.INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (8, 'The Volkswagen', 1938, 'The Volkswagen (German for the "people''s car ") went on to rack up worldwide sales of more than 40 million. A horizontally opposed four-cylinder engine was designed for the power plant, with a total displacement of 996cc. When mounted in the rear and driving the rear wheels, this engine, with its low height, permitted the Volkswagen to have a streamlined, fastback shape. It was air cooled too and came to be loved all over the world as the beetle.', 3);
INSERT INTO automobile_company_carmodels (id, name, year, description, article_id) VALUES (9, 'Aerodynamic Models', 1937, 'From 1930 to 1937, car engines and bodies became large and luxurious. Many 12- and 16-cylinder car s were built. Independent front suspension, which made the big car s more comfortable, appeared in 1933. Also introduced during the 1930s were stronger, more reliable braking systems, and higher compression engines, which developed more horsepower. Mercedes introduced the world''s first diesel car in 1936. Cars on both sides of the Atlantic were styled with gracious proportions, long hoods, and pontoon-shaped fenders. Creative artistry merged with industrial design to produce appealing, aerodynamic car,s.INSERT INTO newCar_new_car (id, name, brand, description, price, engine, horsepower, mileage, image, slug) VALUES (1, 'Mahindra', 'XUV 3XO', 'The Mahindra XUV 3XO is a premium SUV blending luxury with rugged performance. It features a striking exterior design, a plush interior with advanced infotainment, and a powerful engine for dynamic driving. With its state-of-the-art safety and driver-assistance technologies, the XUV 3XO offers a comfortable and secure ride, making it a standout choice for those seeking both style and capability in their vehicle.', 7.49, '1197 cc, 3 Cylinders Inline, 4 Valves/Cylinder, DOHC', 20, 18.89, 'cars/mahidra_new_cars.jpg', '1');
INSERT INTO newCar_new_car (id, name, brand, description, price, engine, horsepower, mileage, image, slug) VALUES (2, 'Toyota Prius', 'Toyota', 'A hybrid vehicle with outstanding fuel efficiency', 30, '1.8 Hybrid', 121, 25, 'cars/Toyota_Prius.jpg', 'toyota-prius');
INSERT INTO newCar_new_car (id, name, brand, description, price, engine, horsepower, mileage, image, slug) VALUES (3, 'Audi TT 2.0 TFSI', 'Audi', 'The Audi TT 2.0 TFSI is a captivating blend of sporty performance and luxurious design. With its sleek coupe body and aerodynamic lines, it commands attention on the road. Under the hood, the 2.0 TFSI engine delivers exhilarating power and dynamic handling, making every drive an engaging experience. Inside, the TT boasts a high-quality, driver-focused interior with advanced technology and premium materials, ensuring both comfort and sophistication. Whether you’re carving through winding roads or cruising on the highway, the Audi TT 2.0 TFSI offers a perfect combination of performance and luxury', 45, '2.0 TFSI', 211, 10, 'cars/Audi_TT_.jpg', 'audi-tt-2-0-tfsi');
INSERT INTO newCar_upcomingcar (id, name, brand, engine, power_torque, estimated_price, expected_launch, description, image, slug, dimensions, kerb_weight) VALUES (1, 'Tata Safari Storme', 'Tata', '2.2 DiCOR diesel engine', '1,40 bhp/ 32.6 kgm', 'Rs. 11,00,000', 'Early 2024', 'The Tata Safari Storme is a modified version of the older Tata Safari with styling changes, a new X2 platform, and improved noise insulation and handling.', 'cars/Tata_sierra.jpg', 'tata-safari-storme', NULL, NULL);
INSERT INTO newCar_upcomingcar (id, name, brand, engine, power_torque, estimated_price, expected_launch, description, image, slug, dimensions, kerb_weight) VALUES (2, 'Toyata Camry', 'Toyata', '2.5 litre VVT-i motor', '1, 67 bhp/ 23 kgm', 'Rs. 20,00,000', 'August 2024', 'The Toyota Camry features luxurious interiors, spacious design, and combines six-speed automatic and manual transmissions with a petrol engine.', 'cars/toyota-camry.jpg', 'toyota-camry', NULL, NULL);
INSERT INTO newCar_upcomingcar (id, name, brand, engine, power_torque, estimated_price, expected_launch, description, image, slug, dimensions, kerb_weight) VALUES (3, 'Volkswagen Beetle', 'Volkswagen', '1.4 litre turbo petrol or 2 litre diesel', '1, 58 bhp/ 24.5 kgm (petrol), 1, 38 bhp/ 32.6 kgm (diesel)', 'Rs. 3600000', 'late 2024', 'The Volkswagen Beetle combines a vintage look with modern features, including crystal clear headlamps and a touch screen infotainment system.', 'cars/volkswagen-beetle.jpg', 'volkswagen-beetle', '4,278 mm/ 2,021 mm/ 2,048 mm', '1,360 Kg');
