INSERT INTO newCar_new_car_feature (id, car_id, feature) VALUES (3, 2, 'The Toyota Prius offers advanced hybrid technology with its Hybrid Synergy Drive system, blending a petrol engine with electric motors for exceptional fuel efficiency. It includes features like regenerative braking, a touchscreen display, Bluetooth connectivity, and a smart key system for convenience. The vehicle also boasts LED headlights, adaptive cruise control, lane departure alert, automatic climate control, and a rearview camera, ensuring a blend of innovation, comfort, and safety.');
