INSERT INTO truck_truckoverview (id, title, content, image) VALUES (1, 'Trucks in India: The Backbone of Transportation', 'Trucks play a vital role in India''s transportation and logistics sector. From heavy-duty commercial vehicles to light commercial vehicles, trucks form the backbone of goods movement across the country. The Indian truck industry has evolved significantly over the years, offering various types of trucks for different applications.', 'truck_overview_images/trucks.jpg');
INSERT INTO truck_trucktype (id, name, description) VALUES (1, 'Heavy Commercial Vehicles', 'Large trucks with GVW above 16 tons, used for long-haul transportation and heavy cargo movement.');
INSERT INTO truck_trucktype (id, name, description) VALUES (2, 'Medium Commercial Vehicles', 'Trucks with GVW between 7.5-16 tons, suitable for regional transportation and medium loads.');
INSERT INTO truck_trucktype (id, name, description) VALUES (3, 'Light Commercial Vehicles', 'Small trucks with GVW below 7.5 tons, ideal for last-mile delivery and urban logistics.');
INSERT INTO truck_trucktype (id, name, description) VALUES (4, 'Pickup Trucks', 'Versatile vehicles combining passenger comfort with cargo capacity, popular in rural and semi-urban areas.');
