INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (1, 'BMW Unveils the All-New BMW X7: A Luxurious Adventure Awaits', 'BMW has just launched its latest luxury SUV, the BMW X7. Combining cutting-edge technology with unmatched comfort, the new X7 promises a refined driving experience with advanced features, spacious interiors, and a powerful engine lineup. Ideal for those seeking both performance and elegance in their next adventure.', 'https://example.com/bmw-x7-launch-image.jpg', 'https://example.com/bmw-x7-launch-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (2, 'Tesla Reveals New Model S Plaid: The Fastest Production Car Ever', 'Tesla has introduced the new Model S Plaid, boasting unprecedented acceleration and top speeds. With a refined design and advanced autopilot features, the Model S Plaid sets new standards for electric performance and luxury.', 'https://example.com/tesla-model-s-plaid.jpg', 'https://example.com/tesla-model-s-plaid-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (3, 'Audi Launches the New Audi Q5: A Perfect Blend of Style and Functionality', 'The latest Audi Q5 offers an enhanced driving experience with improved safety features, advanced technology, and a sophisticated design. This SUV is designed to cater to both urban and off-road adventures.', 'https://example.com/audi-q5-launch.jpg', 'https://example.com/audi-q5-launch-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (4, 'Mercedes-Benz Introduces the New E-Class: Innovation Meets Luxury', 'The new Mercedes-Benz E-Class combines elegance with cutting-edge technology. With its updated interior and advanced driver assistance systems, the E-Class sets a new benchmark in the luxury sedan segment.', 'https://example.com/mercedes-e-class.jpg', 'https://example.com/mercedes-e-class-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (5, 'Ford Debuts the 2024 Mustang GT: Power and Performance Redefined', 'The 2024 Ford Mustang GT brings a new level of performance to the iconic muscle car. Featuring a redesigned exterior and a more powerful engine, the Mustang GT continues to deliver an exhilarating driving experience.', 'https://example.com/ford-mustang-gt.jpg', 'https://example.com/ford-mustang-gt-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (6, 'Chevrolet Unveils the New Corvette Z06: Track-Ready Excellence', 'Chevrolet has introduced the Corvette Z06, designed for those who demand the ultimate performance. With its track-ready features and powerful engine, the Corvette Z06 promises a thrilling driving experience.', 'https://example.com/corvette-z06.jpg', 'https://example.com/corvette-z06-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (8, 'Porsche Launches the 2024 Porsche 911: Iconic Design and Modern Performance', 'The new Porsche 911 continues to impress with its classic design and updated performance features. The 2024 model offers enhanced handling and advanced technology, maintaining its status as a performance icon.', 'https://example.com/porsche-911.jpg', 'https://example.com/porsche-911-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (9, 'Jaguar Introduces the New F-Pace: Luxury and Innovation Combined', 'Jaguar’s latest F-Pace offers a blend of luxury and innovation, featuring a redesigned interior and advanced tech features. This SUV is designed to provide a sophisticated driving experience.', 'https://example.com/jaguar-f-pace.jpg', 'https://example.com/jaguar-f-pace-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (10, 'Land Rover Launches the New Range Rover Sport: Adventure Awaits', 'The new Range Rover Sport is ready for any adventure with its rugged design and advanced off-road capabilities. It combines luxury with versatility, making it perfect for both urban and off-road driving.', 'https://example.com/range-rover-sport.jpg', 'https://example.com/range-rover-sport-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (11, 'Hyundai Reveals the 2024 Hyundai Elantra: A Modern Sedan Experience', 'The 2024 Hyundai Elantra brings a fresh design and enhanced features to the sedan market. With its modern look and advanced technology, the Elantra is designed to offer a refined driving experience.', 'https://example.com/hyundai-elantra.jpg', 'https://example.com/hyundai-elantra-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (12, 'Nissan Introduces the New Nissan Altima: Comfort and Innovation', 'Nissan’s latest Altima model offers a blend of comfort and innovation. With a redesigned interior and updated tech features, the Altima is positioned as a top choice for modern drivers.', 'https://example.com/nissan-altima.jpg', 'https://example.com/nissan-altima-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (13, 'Subaru Launches the 2024 Subaru Outback: Ready for Any Journey', 'The new Subaru Outback is designed for those who seek adventure. With its rugged design and advanced safety features, the Outback is ready to tackle any journey while providing a comfortable ride.', 'https://example.com/subaru-outback.jpg', 'https://example.com/subaru-outback-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (14, 'Kia Unveils the New Kia Sportage: Style Meets Functionality', 'Kia’s latest Sportage model combines stylish design with practical features. With its modern look and advanced technology, the Sportage is set to attract attention in the compact SUV segment.', 'https://example.com/kia-sportage.jpg', 'https://example.com/kia-sportage-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (15, 'Volkswagen Introduces the 2024 VW Tiguan: A New Standard in SUVs', 'The 2024 VW Tiguan offers a new level of sophistication and performance. With its updated design and advanced features, the Tiguan sets a new standard for compact SUVs.', 'https://example.com/vw-tiguan.jpg', 'https://example.com/vw-tiguan-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (16, 'Mazda Launches the New Mazda CX-5: Refined Performance and Comfort', 'Mazda’s latest CX-5 combines refined performance with exceptional comfort. With its sleek design and advanced technology, the CX-5 is designed to offer a premium driving experience.', 'https://example.com/mazda-cx-5.jpg', 'https://example.com/mazda-cx-5-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (17, 'Chrysler Reveals the New Pacifica Hybrid: Family-Friendly and Efficient', 'The new Chrysler Pacifica Hybrid offers a family-friendly design with hybrid efficiency. With its spacious interior and advanced features, the Pacifica Hybrid is perfect for modern families.', 'https://example.com/chrysler-pacifica-hybrid.jpg', 'https://example.com/chrysler-pacifica-hybrid-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (18, 'Buick Introduces the New Enclave: A Luxurious Family SUV', 'Buick’s latest Enclave model offers a luxurious and spacious interior, combined with advanced technology. The new Enclave is designed to provide comfort and style for the entire family.', 'https://example.com/buick-enclave.jpg', 'https://example.com/buick-enclave-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (19, 'GMC Launches the 2024 GMC Sierra: Power and Capability Redefined', 'The 2024 GMC Sierra brings new levels of power and capability to the truck market. With its updated design and enhanced features, the Sierra is ready for any challenge.', 'https://example.com/gmc-sierra.jpg', 'https://example.com/gmc-sierra-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (20, 'Acura Unveils the New MDX: Advanced Technology Meets Luxury', 'The new Acura MDX offers a luxurious driving experience with advanced technology and refined design. The MDX is designed to provide comfort and sophistication for discerning drivers.', 'https://example.com/acura-mdx.jpg', 'https://example.com/acura-mdx-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (21, 'Toyota Launches the 2024 Toyota Highlander: A Family SUV with Advanced Features', 'The 2024 Toyota Highlander offers a spacious interior and advanced features for families. With its updated design and technology, the Highlander is set to be a top choice in the SUV segment.', 'https://example.com/toyota-highlander.jpg', 'https://example.com/toyota-highlander-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (22, 'Genesis Introduces the New G80: Elegance and Innovation Combined', 'Genesis has launched the new G80, offering a blend of elegance and innovation. With its refined design and advanced features, the G80 sets a new standard in luxury sedans.', 'https://example.com/genesis-g80.jpg', 'https://example.com/genesis-g80-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (23, 'Infiniti Reveals the 2024 QX60: A Premium SUV with Enhanced Features', 'The 2024 Infiniti QX60 combines premium features with advanced technology. With its luxurious interior and sophisticated design, the QX60 is designed to deliver a top-tier driving experience.', 'https://example.com/infiniti-qx60.jpg', 'https://example.com/infiniti-qx60-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (24, 'Mitsubishi Launches the New Outlander PHEV: Efficiency Meets Versatility', 'The new Mitsubishi Outlander PHEV offers an efficient and versatile driving experience. With its updated hybrid technology and spacious interior, the Outlander PHEV is perfect for modern drivers.', 'https://example.com/mitsubishi-outlander-phev.jpg', 'https://example.com/mitsubishi-outlander-phev-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (25, 'Rivian Unveils the R1T: A Revolutionary Electric Adventure Truck', 'Rivian has introduced the R1T, an electric adventure truck that promises to revolutionize the market. With its rugged design and impressive performance, the R1T is designed for adventure enthusiasts.', 'https://example.com/rivian-r1t.jpg', 'https://example.com/rivian-r1t-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (26, 'Lucid Motors Reveals the Air: A New Era of Luxury Electric Sedans', 'Lucid Motors has launched the Air, a luxury electric sedan that sets new standards for performance and comfort. With its sleek design and advanced technology, the Air is poised to make a significant impact in the electric vehicle market.', 'https://example.com/lucid-air.jpg', 'https://example.com/lucid-air-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (27, 'Polestar Introduces the Polestar 2: Cutting-Edge Electric Performance', 'The Polestar 2 offers cutting-edge electric performance with a focus on sustainability and technology. Designed to provide a dynamic driving experience, the Polestar 2 is a strong contender in the electric vehicle market.', 'https://example.com/polestar-2.jpg', 'https://example.com/polestar-2-news', '2025-12-24 08:53:31.513532');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (28, 'Ford Reveals the New F-150 Lightning: Power Meets Efficiency', 'The new Ford F-150 Lightning combines the power of the iconic F-150 with the efficiency of electric propulsion. With its advanced features and impressive capabilities, the F-150 Lightning is set to lead the electric truck market.', 'https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=400&h=250&fit=crop', 'https://example.com/ford-f150-lightning-news', '2026-01-23 06:53:13.057475');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (29, 'Chevrolet Launches the Bolt EUV: Compact Electric SUV with Advanced Features', 'Chevrolet’s Bolt EUV offers a compact yet versatile electric SUV option. With its modern design and advanced features, the Bolt EUV is perfect for drivers looking for an efficient and stylish electric vehicle.', 'https://images.unsplash.com/photo-1593941170944-2c2ba0c3ce2c?w=400&h=250&fit=crop', 'https://example.com/chevrolet-bolt-euv-news', '2026-01-23 07:53:13.057475');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (30, 'Hyundai Unveils the Ioniq 5: Futuristic Design and Electric Performance', 'The Hyundai Ioniq 5 showcases a futuristic design combined with advanced electric performance. With its spacious interior and innovative technology, the Ioniq 5 is designed to make a statement in the electric vehicle market.', 'https://images.unsplash.com/photo-1554212610-a0de42134a3e?w=400&h=250&fit=crop', 'https://example.com/hyundai-ioniq-5-news', '2026-01-23 08:53:13.057475');
INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (31, 'Tata Motors Launches New Electric Vehicle', 'Tata Motors has announced the launch of its latest electric vehicle, marking a significant step in India''s EV revolution.', 'https://via.placeholder.com/400x200/007bff/ffffff?text=Tata+EV+News', 'https://example.com/tata-ev-news', '2026-01-23 12:38:15.746158');
