INSERT INTO automobile_company_news (id, title, summary, image_url, url, pub_date) VALUES (33, 'Hyundai Expands Manufacturing in India', 'Hyundai Motor India announces expansion plans for its manufacturing facility in Tamil Nadu.', 'https://via.placeholder.com/400x200/dc3545/ffffff?text=Hyundai+Expand', 'https://example.com/hyundai-expansion', '2026-01-23 12:38:15.746185');
