INSERT INTO pages_autonews (id, title, content, category, pub_date, image) VALUES (1, 'Top 10 Car Maintenance Tips for 2024', 'Regular car maintenance is essential for keeping your vehicle in top condition. Here are the top 10 tips every car owner should follow: 1. Check oil levels regularly, 2. Rotate tires every 5,000-7,500 miles, 3. Replace air filters, 4. Check brake fluid, 5. Test battery health, 6. Inspect belts and hoses, 7. Keep tires properly inflated, 8. Change spark plugs, 9. Check coolant levels, 10. Follow manufacturer service schedule.', 'care_tips', '2026-01-13 11:08:50.184490', 'auto_news/car_care_tips.jpg');
INSERT INTO pages_autonews (id, title, content, category, pub_date, image) VALUES (2, 'India Automobile Industry Sees Record Growth in 2024', 'The Indian automobile industry has experienced unprecedented growth in 2024, with electric vehicle sales reaching new heights. Major manufacturers like Tata Motors, Mahindra & Mahindra, and Maruti Suzuki have reported significant increases in production and sales. The government''s push for electric mobility and favorable policies have contributed to this growth, making India one of the fastest-growing automobile markets globally.', 'industry_news', '2026-01-13 11:08:50.196350', 'auto_news/industry_news.jpg');
INSERT INTO pages_autonews (id, title, content, category, pub_date, image) VALUES (3, 'How to Improve Your Car''s Fuel Efficiency', 'With rising fuel prices, improving your car''s fuel efficiency has become more important than ever. Here are some practical tips: maintain proper tire pressure, remove excess weight, drive smoothly, use cruise control on highways, keep your engine tuned, use the right motor oil, avoid excessive idling, plan trips efficiently, use air conditioning wisely, and consider carpooling for daily commutes.', 'care_tips', '2026-01-13 11:08:50.206002', 'auto_news/car_care_tips.jpg');
INSERT INTO pages_autonews (id, title, content, category, pub_date, image) VALUES (4, 'Electric Vehicle Revolution in India', 'India is witnessing a massive shift towards electric vehicles, with both established and new players investing heavily in EV technology. The government''s FAME-II scheme and state-level incentives have accelerated this transition. Companies like Tata Nexon, Mahindra eVerito, and Ola Electric are leading the charge in making EVs accessible to the common man.', 'industry_news', '2026-01-13 11:08:50.215837', '');
INSERT INTO pages_autonews (id, title, content, category, pub_date, image) VALUES (5, 'Winter Car Care Essentials', 'Winter brings unique challenges for car owners. Essential winter car care includes: checking antifreeze levels, using winter-grade oil, replacing worn wiper blades, checking tire pressure (cold air reduces pressure), keeping gas tank at least half full, testing battery health, using winter tires in snowy regions, keeping emergency supplies in the car, and allowing engine to warm up before driving.', 'care_tips', '2026-01-13 11:08:50.225203', 'auto_news/car_care_tips.jpg');
